// This is needed because emotion/server uses Buffer which is not available in browsers
if (typeof globalThis !== 'undefined' && !globalThis.Buffer) {
  // Create a minimal Buffer polyfill that satisfies emotion/server's needs
  class BufferPolyfill {
    static isBuffer() {
      return false;
    }
    static from() {
      return new BufferPolyfill();
    }
  }
  globalThis.Buffer = BufferPolyfill as any;
}

