     1→import { useEffect, createElement } from "react";
     2→import { MockLink } from "@apollo/client/testing";
     3→import {
     4→  MockedProvider,
     5→  MockedProviderProps,
     6→} from "@apollo/client/testing/react";
     7→import {
     8→  act,
     9→  fireEvent,
    10→  queries,
    11→  render,
    12→  renderHook,
    13→  screen,
    14→  waitFor,
    15→  within,
    16→  waitForElementToBeRemoved,
    17→  type RenderOptions,
    18→  type RenderResult,
    19→} from "@testing-library/react";
    20→import userEvent from "@testing-library/user-event";
    21→import { RouterProvider, createMemoryRouter } from "react-router-dom";
    22→import * as customQueries from "./custom-queries";
    23→
    24→type QueriesType = typeof queries;
    25→type CustomQueriesType = typeof customQueries;
    26→type CustomRenderType = CustomQueriesType & QueriesType;
    27→type CustomRenderOptions = RenderOptions<CustomRenderType>;
    28→
    29→interface RenderWithRouterMatchOptions extends CustomRenderOptions {
    30→  route?: string;
    31→  history?: unknown;
    32→  path?: string;
    33→}
    34→
    35→// Bind our custom queries to screen.
    36→// https://github.com/testing-library/dom-testing-library/issues/516
    37→const boundQueries = within<typeof customQueries>(document.body, customQueries);
    38→const customScreen = { ...screen, ...boundQueries };
    39→
    40→/**
    41→ * `customRender` or `render` takes an instance of react-testing-library's render method
    42→ *  and adds additional selectors for querying components in tests.
    43→ * @param ui - React Component to render
    44→ * @param options - Options to pass to render
    45→ * @returns RenderResult with custom queries bound to screen
    46→ */
    47→const customRender = (ui: React.ReactElement, options?: CustomRenderOptions) =>
    48→  render(ui, {
    49→    queries: { ...queries, ...customQueries },
    50→    ...options,
    51→  }) as RenderResult<CustomRenderType>;
    52→
    53→const customWithin = (ui: HTMLElement) =>
    54→  within(ui, { ...queries, ...customQueries });
    55→
    56→/**
    57→ * `renderWithRouterMatch` implements the `customRender` method and wraps a component
    58→ * with an instance of `react-router`'s `<Router />` component.
    59→ * @param ui - React Component to render
    60→ * @param options - Options to pass to render
    61→ * @returns RenderResult with custom queries bound to screen
    62→ */
    63→const renderWithRouterMatch = (
    64→  ui: React.ReactElement,
    65→  options: RenderWithRouterMatchOptions = {},
    66→) => {
    67→  const { path = "/", route = "/", wrapper: TestWrapper, ...rest } = options;
    68→
    69→  const getMemoryRouter = (element: React.ReactElement) => {
    70→    const routes = [
    71→      {
    72→        element: TestWrapper ? <TestWrapper>{element}</TestWrapper> : element,
    73→        errorElement: <div>Failed to render component.</div>,
    74→        path,
    75→      },
    76→      {
    77→        element: <div>Not found</div>,
    78→        path: "*",
    79→      },
    80→    ];
    81→    return createMemoryRouter(routes, {
    82→      initialEntries: [route],
    83→    });
    84→  };
    85→
    86→  const memoryRouter = getMemoryRouter(ui);
    87→
    88→  const { rerender, ...renderRest } = customRender(
    89→    <RouterProvider router={memoryRouter} />,
    90→    {
    91→      ...rest,
    92→    },
    93→  );
    94→
    95→  const customRerender = (element: React.ReactElement) => {
    96→    rerender(<RouterProvider router={getMemoryRouter(element)} />);
    97→  };
    98→
    99→  return {
   100→    rerender: customRerender,
   101→    router: memoryRouter,
   102→    ...renderRest,
   103→  };
   104→};
   105→
   106→/**
   107→ * `renderComponentWithHook` is a utility function that renders a component with a given hook for use in testing
   108→ * @param useHook - The hook to use
   109→ * @param Comp - The component to render
   110→ * @returns - The component and the hook result accessible via hook.current
   111→ */
   112→const renderComponentWithHook = <
   113→  T extends () => unknown,
   114→  U extends React.JSX.Element | null,
   115→>(
   116→  useHook: T,
   117→  Comp: U,
   118→) => {
   119→  const hookRef: { current?: ReturnType<T> } = { current: undefined };
   120→
   121→  const TestComponent = () => {
   122→    const hookResult = useHook();
   123→    useEffect(() => {
   124→      hookRef.current = hookResult as ReturnType<T>;
   125→    });
   126→    return Comp;
   127→  };
   128→
   129→  return {
   130→    Component: TestComponent,
   131→    hook: hookRef as { current: ReturnType<T> },
   132→  };
   133→};
   134→
   135→/**
   136→ * `stubGetClientRects` fixes a fallbackFocus error introduced by focus-trap.
   137→ * focus-trap only offers legacy CommonJS exports so it can't be mocked by Vitest.
   138→ * Instead, spoof focus-trap into thinking there is a node attached.
   139→ * https://stackoverflow.com/a/75527964
   140→ */
   141→const stubGetClientRects = () => {
   142→  const { getClientRects } = HTMLElement.prototype;
   143→  HTMLElement.prototype.getClientRects = function () {
   144→    return {
   145→      ...getClientRects.apply(this),
   146→      length: 1,
   147→    };
   148→  };
   149→};
   150→
   151→/**
   152→ * createWrapper provides a generic way to pass props to a React Component wrapper.
   153→ * @param Wrapper - Wrapper component
   154→ * @param props - props to be spread on wrapper
   155→ * @returns - wrapper with props applied
   156→ */
   157→const createWrapper = <T extends Record<string, unknown>>(
   158→  Wrapper: React.ComponentType<React.PropsWithChildren<T>>,
   159→  props: T,
   160→) =>
   161→  function CreatedWrapper({ children }: React.PropsWithChildren) {
   162→    return createElement(Wrapper, props, children);
   163→  };
   164→
   165→type MockedResponse = MockLink.MockedResponse;
   166→
   167→export {
   168→  act,
   169→  fireEvent,
   170→  customRender as render,
   171→  renderHook,
   172→  renderWithRouterMatch,
   173→  renderComponentWithHook,
   174→  customScreen as screen,
   175→  userEvent,
   176→  waitFor,
   177→  waitForElementToBeRemoved,
   178→  customWithin as within,
   179→  stubGetClientRects,
   180→  createWrapper,
   181→  MockedProvider,
   182→  type MockedResponse,
   183→  type MockedProviderProps,
   184→};
   185→
   186→export type { RenderWithRouterMatchOptions };
   187→

